import s from './Header.module.css';

const Header = () => {
    return (
        <header className={s.header}>
        <img src='https://encrypted-tbn0.gstatic.com/images?q=tbn%3AANd9GcRs0nir0O5z0j39qXCIJ8saZ6az8If7-VPgKA&usqp=CAU' />
      </header>
    )

}
export default Header ;
